class Solution:
    def kthCharacter(self, k: int, operations: List[int]) -> str:
        length = 1
        shift = 0
        for op in reversed(operations):
            if k > length:
                k -= length
                if op == 1:
                    shift += 1
                length *= 2
            else:
                break
        return chr((ord('a') + (k - 1 + shift)) % 26 + ord('a'))
```

